) as (
  values
  (
    'part-1-daily-routine',
    1,
    $$What is your daily routine like?$$,
    $$Mention two regular activities and say how you feel about your routine.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$My daily routine is quite simple. I usually get up around seven, have breakfast, and then start studying or working. In the evening, I try to exercise or watch something relaxing. It is not very exciting, but it helps me stay organised.$$,
    $$My routine is fairly structured during the week. I normally get up around seven, check my schedule, and spend the morning on study or work tasks. In the evening, I try to go for a short walk because it helps me clear my head after sitting for a long time.$$,
    $$On weekdays my routine is quite predictable, but I actually like that. I usually start the day by checking the most urgent tasks, then I work or study in focused blocks. Later in the day, I try to protect some time for exercise or a quiet meal. That balance keeps me productive without feeling completely drained.$$,
    $$[{"phrase":"fairly structured","meaning":"organised in a clear way","example":"My weekdays are fairly structured."},{"phrase":"clear my head","meaning":"relax and think more clearly","example":"Walking helps me clear my head."},{"phrase":"focused blocks","meaning":"periods of concentrated work","example":"I study in focused blocks."},{"phrase":"feel drained","meaning":"feel very tired","example":"I feel drained after a full day online."}]$$::jsonb,
    $$[{"insteadOf":"same every day","try":["predictable","routine-based","consistent"],"meaning":"following a regular pattern","example":"My schedule is quite predictable.","context":"daily routines"},{"insteadOf":"very busy","try":["packed","demanding","full"],"meaning":"having many things to do","example":"My mornings are usually packed.","context":"busy schedules"},{"insteadOf":"relax","try":["unwind","switch off","clear my head"],"meaning":"rest mentally","example":"I unwind by listening to music.","context":"after a long day"}]$$::jsonb,
    $$[{"pattern":"I usually start the day by ___.","example":"I usually start the day by checking my schedule.","suitableUse":"Describing morning habits."},{"pattern":"What helps me stay ___ is ___.","example":"What helps me stay organised is planning the night before.","suitableUse":"Explaining a useful routine."},{"pattern":"It is not exactly ___, but it ___.","example":"It is not exactly exciting, but it keeps me focused.","suitableUse":"Adding a balanced comment."}]$$::jsonb,
    $$[{"incorrect":"Every day I am wake up at seven.","better":"Every day I wake up at seven.","why":"Use wake up as the main verb, not am wake up."},{"incorrect":"My routine is very same.","better":"My routine is very similar every day.","why":"Use similar, not same, after very."},{"incorrect":"I do exercise for relax.","better":"I exercise to relax.","why":"Use to + verb for purpose."}]$$::jsonb
  ),
  (
    'part-1-daily-routine',
    2,
    $$Would you like to change your routine?$$,
    $$Say yes or no, then explain one specific change.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$Yes, I would like to change it a little. I want to sleep earlier because I sometimes stay up too late using my phone. If I slept earlier, I think I would have more energy in the morning and study better.$$,
    $$I would not change everything, but I would like to make my evenings healthier. At the moment, I sometimes spend too much time scrolling on my phone. I would prefer to read or prepare for the next day, because that would make my mornings feel less rushed.$$,
    $$I would keep the basic structure, but I would definitely improve the way I end the day. I have a bad habit of checking my phone when I should be winding down. Ideally, I would replace that with reading or planning the next morning, so I could sleep better and start the day with a calmer mindset.$$,
    $$[{"phrase":"make my evenings healthier","meaning":"improve evening habits","example":"I want to make my evenings healthier."},{"phrase":"feel less rushed","meaning":"feel calmer and not hurried","example":"Planning ahead makes my mornings feel less rushed."},{"phrase":"wind down","meaning":"relax before sleeping","example":"I try to wind down before bed."},{"phrase":"a calmer mindset","meaning":"a more peaceful way of thinking","example":"Exercise gives me a calmer mindset."}]$$::jsonb,
    $$[{"insteadOf":"sleep more early","try":["sleep earlier","go to bed earlier","keep a better sleep schedule"],"meaning":"rest at an earlier time","example":"I want to go to bed earlier.","context":"sleep habits"},{"insteadOf":"play phone","try":["scroll on my phone","use my phone","check social media"],"meaning":"spend time on a phone","example":"I scroll on my phone too much at night.","context":"phone use"},{"insteadOf":"change a little","try":["make a small adjustment","improve one habit","change one part"],"meaning":"not change everything","example":"I would make a small adjustment to my evening routine.","context":"small routine changes"}]$$::jsonb,
    $$[{"pattern":"I would keep ___, but I would change ___.","example":"I would keep my morning routine, but I would change my evenings.","suitableUse":"Giving a balanced answer."},{"pattern":"At the moment, I sometimes ___.","example":"At the moment, I sometimes stay up too late.","suitableUse":"Explaining current habits."},{"pattern":"Ideally, I would replace ___ with ___.","example":"Ideally, I would replace phone time with reading.","suitableUse":"Describing a desired change."}]$$::jsonb,
    $$[{"incorrect":"I want sleep earlier.","better":"I want to sleep earlier.","why":"Use want to + verb."},{"incorrect":"I spend many time on phone.","better":"I spend a lot of time on my phone.","why":"Use a lot of time, and my phone."},{"incorrect":"It can let me more energy.","better":"It can give me more energy.","why":"Give me more energy is the natural collocation."}]$$::jsonb
  ),
  (
    'part-1-weekends',
    1,
    $$What do you usually do at weekends?$$,
    $$Give two activities and say why you enjoy them.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$At weekends, I usually sleep a little later and meet friends if I have time. Sometimes we go to a cafe or walk around a shopping area. I also try to clean my room because it makes the next week feel more organised.$$,
    $$My weekends are usually a mix of rest and small errands. I like sleeping in a bit, then meeting a friend for coffee or going for a walk. I also use Sunday evening to tidy up and plan the week, because that helps me feel less stressed on Monday.$$,
    $$I try to keep my weekends flexible. If I have had a tiring week, I might sleep in, cook something simple, and avoid making too many plans. But if I feel energetic, I like meeting friends or exploring a new cafe. I also do a quick reset on Sunday night, so Monday does not feel chaotic.$$,
    $$[{"phrase":"a mix of rest and errands","meaning":"some relaxing activities and some practical tasks","example":"My weekend is a mix of rest and errands."},{"phrase":"sleep in","meaning":"wake up later than usual","example":"I like to sleep in on Saturdays."},{"phrase":"do a quick reset","meaning":"prepare and tidy before a new week","example":"I do a quick reset on Sunday night."},{"phrase":"feel chaotic","meaning":"feel disorganised or stressful","example":"Monday feels chaotic if I do not prepare."}]$$::jsonb,
    $$[{"insteadOf":"go outside","try":["meet friends","go for a walk","explore a new cafe"],"meaning":"spend time out of the house","example":"I often explore a new cafe at weekends.","context":"weekend activities"},{"insteadOf":"clean things","try":["tidy up","do housework","organise my room"],"meaning":"make a space clean and orderly","example":"I tidy up on Sunday evening.","context":"household chores"},{"insteadOf":"very tired week","try":["a tiring week","a demanding week","a busy week"],"meaning":"a week that uses a lot of energy","example":"After a demanding week, I prefer to stay home.","context":"after a demanding week"}]$$::jsonb,
    $$[{"pattern":"My weekends are usually a mix of ___ and ___.","example":"My weekends are usually a mix of rest and errands.","suitableUse":"Describing weekend routines."},{"pattern":"If I feel ___, I usually ___.","example":"If I feel energetic, I usually meet friends.","suitableUse":"Giving flexible habits."},{"pattern":"I use ___ to ___.","example":"I use Sunday evening to plan the week.","suitableUse":"Explaining time use."}]$$::jsonb,
    $$[{"incorrect":"At weekend I meet friend.","better":"At weekends, I meet friends.","why":"Use at weekends and plural friends for a general habit."},{"incorrect":"I sleep lately.","better":"I sleep in. / I wake up later.","why":"Lately means recently, not late in the morning."},{"incorrect":"I make my room clean.","better":"I clean my room. / I tidy my room.","why":"Use clean or tidy as the verb."}]$$::jsonb
  ),
  (
    'part-1-weekends',
    2,
    $$Do you prefer busy weekends or quiet weekends?$$,
    $$Choose one and explain when your preference changes.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I prefer quiet weekends most of the time. I like staying at home, watching videos, and cooking something easy. However, if I have been alone for many days, I enjoy going out with friends because it makes me feel refreshed.$$,
    $$I generally prefer quiet weekends because weekdays can already be quite busy. I enjoy having time to cook, read, or simply do nothing for a while. That said, I still need some social time, so I might arrange one meal with friends instead of filling the whole weekend with plans.$$,
    $$I lean towards quiet weekends, especially after a demanding week. I find that a slower pace helps me recover properly instead of just moving from one plan to another. Still, I do not want every weekend to be completely silent. A simple dinner with friends is enough to make me feel connected without leaving me exhausted.$$,
    $$[{"phrase":"lean towards","meaning":"slightly prefer","example":"I lean towards quiet weekends."},{"phrase":"a slower pace","meaning":"a calmer speed of life","example":"A slower pace helps me relax."},{"phrase":"social time","meaning":"time spent with other people","example":"I still need some social time."},{"phrase":"feel connected","meaning":"feel close to other people","example":"Dinner with friends makes me feel connected."}]$$::jsonb,
    $$[{"insteadOf":"busy weekend","try":["packed weekend","active weekend","full schedule"],"meaning":"a weekend with many plans","example":"I do not like a packed weekend every week.","context":"weekend plans"},{"insteadOf":"quiet weekend","try":["slow weekend","relaxed weekend","low-key weekend"],"meaning":"a calm weekend","example":"I prefer a low-key weekend.","context":"low-key weekends"},{"insteadOf":"very tired","try":["exhausted","drained","worn out"],"meaning":"having little energy","example":"Too many plans leave me exhausted.","context":"low energy"}]$$::jsonb,
    $$[{"pattern":"I generally prefer ___ because ___.","example":"I generally prefer quiet weekends because weekdays are busy.","suitableUse":"Answering preference questions."},{"pattern":"That said, I still ___.","example":"That said, I still enjoy meeting friends sometimes.","suitableUse":"Adding balance."},{"pattern":"A simple ___ is enough to ___.","example":"A simple walk is enough to help me relax.","suitableUse":"Explaining a moderate preference."}]$$::jsonb,
    $$[{"incorrect":"I prefer quiet weekend.","better":"I prefer quiet weekends.","why":"Use plural weekends for a general preference."},{"incorrect":"I need to relax myself.","better":"I need to relax.","why":"Relax is usually used without myself."},{"incorrect":"It makes me not tired.","better":"It helps me feel less tired.","why":"This sounds more natural and precise."}]$$::jsonb
  ),
  (
    'part-1-cooking',
    1,
    $$Do you like cooking?$$,
    $$Say how often you cook and what kind of food you make.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$Yes, I like cooking, but I am not very advanced. I usually cook simple dishes like noodles, eggs, or vegetables. I enjoy it because it is cheaper than eating out, and I can choose what ingredients I want to use.$$,
    $$Yes, I enjoy cooking when I have enough time. I usually make simple home-style dishes, especially rice, vegetables, and soup. I am not a creative cook, but I like the feeling of making something warm and healthy for myself instead of ordering takeaway.$$,
    $$I do enjoy cooking, although I would describe myself as practical rather than talented. Most of the time I make quick home-style meals, like stir-fried vegetables or soup. What I like is the control it gives me: I can adjust the taste, use fresher ingredients, and avoid relying on takeaway too often.$$,
    $$[{"phrase":"home-style dishes","meaning":"simple food cooked at home","example":"I usually make home-style dishes."},{"phrase":"ordering takeaway","meaning":"buying prepared food to eat at home","example":"I try not to order takeaway too often."},{"phrase":"practical rather than talented","meaning":"useful but not highly skilled","example":"I am practical rather than talented in the kitchen."},{"phrase":"adjust the taste","meaning":"change flavour to suit yourself","example":"I can adjust the taste when I cook."}]$$::jsonb,
    $$[{"insteadOf":"cook food","try":["make a meal","prepare a dish","cook at home"],"meaning":"prepare food","example":"I make a simple meal after work.","context":"home cooking"},{"insteadOf":"outside food","try":["takeaway","restaurant food","eating out"],"meaning":"food not cooked at home","example":"Cooking is cheaper than eating out.","context":"eating habits"},{"insteadOf":"good materials","try":["fresh ingredients","basic ingredients","healthy ingredients"],"meaning":"foods used in cooking","example":"Fresh ingredients make the dish taste better.","context":"cooking ingredients"}]$$::jsonb,
    $$[{"pattern":"I enjoy cooking when ___.","example":"I enjoy cooking when I have enough time.","suitableUse":"Giving conditions."},{"pattern":"I am not ___, but I ___.","example":"I am not a creative cook, but I can make simple meals.","suitableUse":"Adding realistic balance."},{"pattern":"What I like is the control it gives me: ___.","example":"What I like is the control it gives me: I can use healthier ingredients.","suitableUse":"Explaining benefits."}]$$::jsonb,
    $$[{"incorrect":"I cook by myself food.","better":"I cook for myself.","why":"For myself is the natural phrase."},{"incorrect":"I am not good at cook.","better":"I am not good at cooking.","why":"Use good at + verb-ing."},{"incorrect":"The food is more healthy.","better":"The food is healthier.","why":"Healthier is the comparative adjective."}]$$::jsonb
  ),
  (
    'part-1-cooking',
    2,
    $$Who usually cooks in your family?$$,
    $$Name the person and describe one thing they cook well.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$My mother usually cooks in my family. She is especially good at making soup and simple vegetable dishes. Her food is not fancy, but it tastes comfortable and healthy. I think I learned many basic cooking habits from watching her.$$,
    $$In my family, my mother does most of the cooking, although other people help sometimes. She is very good at making soup because she knows how to balance the flavour without using too much oil or salt. Her cooking feels simple, but it has a very comforting taste.$$,
    $$My mother is still the main cook in my family. What I admire is not that she makes complicated dishes, but that she can turn ordinary ingredients into something balanced and comforting. Her soups are probably the best example. They taste light, but they still feel rich because she understands timing and seasoning really well.$$,
    $$[{"phrase":"does most of the cooking","meaning":"cooks most family meals","example":"My mother does most of the cooking."},{"phrase":"comforting taste","meaning":"a warm and familiar flavour","example":"Her food has a comforting taste."},{"phrase":"balance the flavour","meaning":"make flavours work well together","example":"She knows how to balance the flavour."},{"phrase":"ordinary ingredients","meaning":"simple everyday food items","example":"She uses ordinary ingredients well."}]$$::jsonb,
    $$[{"insteadOf":"delicious food","try":["comforting food","well-balanced dishes","home-cooked meals"],"meaning":"more specific food descriptions","example":"I miss her home-cooked meals.","context":"home-cooked meals"},{"insteadOf":"make soup good","try":["make excellent soup","prepare soup well","season soup nicely"],"meaning":"cook soup skillfully","example":"She seasons soup nicely.","context":"cooking soup"},{"insteadOf":"not special","try":["simple","unfussy","not fancy"],"meaning":"plain but good","example":"Her food is simple but satisfying.","context":"simple food"}]$$::jsonb,
    $$[{"pattern":"In my family, ___ does most of the cooking.","example":"In my family, my father does most of the cooking.","suitableUse":"Identifying a family role."},{"pattern":"What I admire is not ___, but ___.","example":"What I admire is not speed, but consistency.","suitableUse":"Giving a deeper comment."},{"pattern":"___ is probably the best example.","example":"Her soup is probably the best example.","suitableUse":"Introducing a specific dish."}]$$::jsonb,
    $$[{"incorrect":"My mother cooks very well soup.","better":"My mother makes soup very well.","why":"Place very well after the verb phrase."},{"incorrect":"She cooks many delicious.","better":"She cooks many delicious dishes.","why":"Delicious needs a noun."},{"incorrect":"I learn cooking from see her.","better":"I learned cooking by watching her.","why":"Use by + verb-ing."}]$$::jsonb
  ),
  (
    'part-1-public-transport',
    1,
    $$How often do you use public transport?$$,
    $$Mention the type of transport and why you use it.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I use public transport several times a week. I usually take the bus or metro because it is cheaper than driving and I do not need to worry about parking. Sometimes it is crowded, but it is still convenient for daily travel.$$,
    $$I use public transport quite often, especially when I need to go downtown. The metro is usually my first choice because it is reliable and avoids traffic. Buses are useful too, although they can be slower during rush hour. Overall, it is a practical way to get around.$$,
    $$I rely on public transport fairly regularly, mainly for commuting or going into busy areas. The metro is the most convenient option because it is predictable and not affected by traffic in the same way buses are. It is not always comfortable at peak times, but it saves money and reduces the stress of finding parking.$$,
    $$[{"phrase":"get around","meaning":"travel from place to place","example":"Public transport helps me get around."},{"phrase":"rush hour","meaning":"the busiest travel time","example":"Buses are slower during rush hour."},{"phrase":"peak times","meaning":"busy periods","example":"The metro is crowded at peak times."},{"phrase":"reliable and predictable","meaning":"usually on time and easy to plan","example":"The metro is reliable and predictable."}]$$::jsonb,
    $$[{"insteadOf":"traffic time","try":["rush hour","peak travel time","busy period"],"meaning":"a time with many travellers","example":"I avoid travelling during rush hour.","context":"commuting periods"},{"insteadOf":"take car","try":["drive","travel by car","use a private car"],"meaning":"use a car","example":"Driving is less convenient downtown.","context":"transport choices"},{"insteadOf":"many people","try":["crowded","packed","busy"],"meaning":"full of people","example":"The train is packed in the morning.","context":"crowded transport"}]$$::jsonb,
    $$[{"pattern":"I usually take ___ because ___.","example":"I usually take the metro because it avoids traffic.","suitableUse":"Explaining transport choice."},{"pattern":"___ is useful too, although ___.","example":"Buses are useful too, although they can be slow.","suitableUse":"Comparing options."},{"pattern":"It is not always ___, but it ___.","example":"It is not always comfortable, but it saves money.","suitableUse":"Balanced evaluation."}]$$::jsonb,
    $$[{"incorrect":"I take public traffic.","better":"I take public transport.","why":"Public transport is the correct phrase."},{"incorrect":"It is convenience.","better":"It is convenient.","why":"Use the adjective convenient."},{"incorrect":"I by bus go school.","better":"I go to school by bus.","why":"Use go to + place + by bus."}]$$::jsonb
  ),
  (
    'part-1-public-transport',
    2,
    $$Do you prefer travelling by bus or by train?$$,
    $$Choose one and compare it with the other option.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I prefer travelling by train because it is usually faster and more comfortable. Buses are useful for short distances, but they can be delayed by traffic. On trains, I can sit more comfortably and know when I will arrive.$$,
    $$I generally prefer trains, especially for longer journeys. They are usually more spacious, and the schedule is easier to trust. Buses are more flexible because they stop in more neighbourhoods, but they can be uncomfortable when the roads are busy or the weather is bad.$$,
    $$I would choose trains in most situations. They feel more predictable, and I can use the travel time to read or reply to messages without worrying about sudden traffic delays. Buses are better for short local trips because they reach smaller streets, but for comfort and punctuality, trains suit me better.$$,
    $$[{"phrase":"longer journeys","meaning":"trips that take more time or distance","example":"I prefer trains for longer journeys."},{"phrase":"more spacious","meaning":"having more room","example":"Trains are usually more spacious."},{"phrase":"punctuality","meaning":"being on time","example":"Trains are better for punctuality."},{"phrase":"short local trips","meaning":"brief trips nearby","example":"Buses are useful for short local trips."}]$$::jsonb,
    $$[{"insteadOf":"more big space","try":["more spacious","roomier","less cramped"],"meaning":"having more room","example":"The train is less cramped than the bus.","context":"train comfort"},{"insteadOf":"on time","try":["punctual","reliable","easy to schedule"],"meaning":"arriving as expected","example":"The train is usually punctual.","context":"transport reliability"},{"insteadOf":"traffic late","try":["traffic delays","road congestion","being delayed by traffic"],"meaning":"late because roads are busy","example":"Buses can be delayed by traffic.","context":"road delays"}]$$::jsonb,
    $$[{"pattern":"I generally prefer ___, especially for ___.","example":"I generally prefer trains, especially for longer journeys.","suitableUse":"Making a preference specific."},{"pattern":"___ are more ___, but ___.","example":"Buses are more flexible, but trains are more comfortable.","suitableUse":"Comparing two options."},{"pattern":"For ___, ___ suits me better.","example":"For punctuality, trains suit me better.","suitableUse":"Summarising preference."}]$$::jsonb,
    $$[{"incorrect":"Train is more comfortable than bus.","better":"The train is more comfortable than the bus.","why":"Use articles when talking about transport types generally."},{"incorrect":"Bus can late because traffic.","better":"Buses can be late because of traffic.","why":"Use be late and because of + noun."},{"incorrect":"I can arrive in time.","better":"I can arrive on time.","why":"On time means punctual."}]$$::jsonb
  ),
  (
    'part-1-mobile-phones',
    1,
    $$How often do you use your mobile phone?$$,
    $$Give a realistic answer and mention two common uses.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I use my mobile phone every day, probably more than I should. I use it for messages, maps, and checking information. It is very useful, but sometimes it distracts me when I am trying to study or sleep.$$,
    $$I use my phone throughout the day, mainly for messaging, checking my schedule, and looking up information quickly. It is almost like a practical tool now, not just a way to relax. However, I do try to limit it at night because it can affect my sleep.$$,
    $$I use my phone constantly, although I am trying to be more intentional about it. It is useful for everyday tasks like navigation, banking, messages, and quick research. The problem is that the useful parts are mixed with distractions, so I sometimes check it automatically even when I do not really need to.$$,
    $$[{"phrase":"throughout the day","meaning":"during many parts of the day","example":"I check my phone throughout the day."},{"phrase":"look up information","meaning":"search for information","example":"I use my phone to look up information."},{"phrase":"be more intentional","meaning":"use something with more control and purpose","example":"I am trying to be more intentional about screen time."},{"phrase":"check it automatically","meaning":"look at it without thinking","example":"I sometimes check it automatically."}]$$::jsonb,
    $$[{"insteadOf":"use phone many times","try":["use my phone frequently","check my phone often","use it throughout the day"],"meaning":"use it a lot","example":"I use my phone frequently for work.","context":"daily phone habits"},{"insteadOf":"find information","try":["look up information","search quickly","check details"],"meaning":"get information online","example":"I look up directions on my phone.","context":"quick searches"},{"insteadOf":"bad thing","try":["distraction","time-waster","unhealthy habit"],"meaning":"something that takes attention away","example":"Notifications can be a distraction.","context":"phone distractions"}]$$::jsonb,
    $$[{"pattern":"I use my phone mainly for ___.","example":"I use my phone mainly for messages and maps.","suitableUse":"Listing common uses."},{"pattern":"It is almost like ___, not just ___.","example":"It is almost like a practical tool, not just entertainment.","suitableUse":"Adding nuance."},{"pattern":"The problem is that ___.","example":"The problem is that useful apps are mixed with distractions.","suitableUse":"Explaining a downside."}]$$::jsonb,
    $$[{"incorrect":"I use phone every day.","better":"I use my phone every day.","why":"Use my phone or a mobile phone."},{"incorrect":"It makes me distraction.","better":"It distracts me. / It is a distraction.","why":"Use distracts as a verb or distraction as a noun."},{"incorrect":"I search informations.","better":"I search for information.","why":"Information is uncountable."}]$$::jsonb
  ),
  (
    'part-1-mobile-phones',
    2,
    $$Could you live without your mobile phone?$$,
    $$Give a balanced answer, not just yes or no.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I could live without it for a short time, but it would be difficult. I use my phone for maps, messages, and payments, so many daily tasks would become inconvenient. However, I think a short break from it could also be healthy.$$,
    $$I think I could manage for a day or two, but not comfortably for a long time. My phone is connected to transport, banking, communication, and even study reminders. At the same time, being without it briefly might help me focus better and notice how often I check it unnecessarily.$$,
    $$I could probably survive without my phone, but modern life would become much less convenient. So many small tasks are now linked to it, from finding directions to confirming appointments. That said, I would not mind taking short phone-free periods, because they would force me to concentrate and be more present.$$,
    $$[{"phrase":"manage for a day or two","meaning":"handle the situation briefly","example":"I could manage for a day or two without my phone."},{"phrase":"phone-free periods","meaning":"times without using a phone","example":"Phone-free periods help me focus."},{"phrase":"be more present","meaning":"pay attention to the current moment","example":"I feel more present without notifications."},{"phrase":"daily tasks would become inconvenient","meaning":"normal activities would be harder","example":"Without a phone, daily tasks would become inconvenient."}]$$::jsonb,
    $$[{"insteadOf":"cannot live","try":["would struggle","would find it difficult","could manage briefly"],"meaning":"having difficulty without something","example":"I would struggle without maps.","context":"phone dependence"},{"insteadOf":"no phone time","try":["phone-free time","digital break","short break from my phone"],"meaning":"time away from devices","example":"A digital break can be useful.","context":"digital breaks"},{"insteadOf":"many things in phone","try":["many tasks are linked to it","it supports daily tasks","it is part of daily life"],"meaning":"the phone is used for many activities","example":"Many tasks are linked to it now.","context":"daily phone tasks"}]$$::jsonb,
    $$[{"pattern":"I could manage for ___, but ___.","example":"I could manage for one day, but not for a week.","suitableUse":"Giving a measured answer."},{"pattern":"So many small tasks are now linked to ___.","example":"So many small tasks are now linked to mobile apps.","suitableUse":"Explaining dependence."},{"pattern":"That said, I would not mind ___.","example":"That said, I would not mind taking a short break from it.","suitableUse":"Adding balance."}]$$::jsonb,
    $$[{"incorrect":"I can live without phone one day.","better":"I could live without my phone for one day.","why":"Use could for hypothetical situations and for one day."},{"incorrect":"It is inconvenient my life.","better":"It would make my life inconvenient.","why":"Use make + object + adjective."},{"incorrect":"I will focus more good.","better":"I would focus better.","why":"Better is the correct comparative adverb here."}]$$::jsonb
  ),
  (
    'part-1-music',
    1,
    $$What kind of music do you like?$$,
    $$Name a type of music and say when you listen to it.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$I like pop music because it is easy to listen to and helps me relax. I usually listen to it when I am walking or doing simple tasks at home. I do not know much about music, but I enjoy songs with a good melody.$$,
    $$I mostly listen to pop and acoustic music. I like songs that are easy to follow but still have some emotion in the lyrics. I often play music when I am commuting or cooking, because it makes ordinary moments feel a bit more enjoyable.$$,
    $$My taste is quite mixed, but I usually come back to acoustic pop. I like music that feels warm and not too overproduced, especially when the lyrics tell a simple story. I often listen while walking alone, because it gives the journey a calmer mood and helps me process my thoughts.$$,
    $$[{"phrase":"easy to listen to","meaning":"pleasant and not difficult to enjoy","example":"Pop music is easy to listen to."},{"phrase":"ordinary moments","meaning":"normal everyday times","example":"Music makes ordinary moments more enjoyable."},{"phrase":"not too overproduced","meaning":"not sounding too artificial or heavily edited","example":"I like songs that are not too overproduced."},{"phrase":"process my thoughts","meaning":"think through feelings or ideas","example":"Music helps me process my thoughts."}]$$::jsonb,
    $$[{"insteadOf":"good song","try":["catchy song","emotional song","relaxing track"],"meaning":"more specific music descriptions","example":"I like relaxing tracks in the evening.","context":"music preferences"},{"insteadOf":"words of song","try":["lyrics","meaningful lyrics","simple story"],"meaning":"the words in music","example":"I like meaningful lyrics.","context":"song lyrics"},{"insteadOf":"music type","try":["genre","style","acoustic pop"],"meaning":"category of music","example":"My favourite genre is acoustic pop.","context":"music genres"}]$$::jsonb,
    $$[{"pattern":"I mostly listen to ___.","example":"I mostly listen to pop and acoustic music.","suitableUse":"Naming music preferences."},{"pattern":"I like songs that ___.","example":"I like songs that have meaningful lyrics.","suitableUse":"Describing qualities."},{"pattern":"I often play music when ___.","example":"I often play music when I am cooking.","suitableUse":"Linking music to routine."}]$$::jsonb,
    $$[{"incorrect":"I like listen music.","better":"I like listening to music.","why":"Use listen to music."},{"incorrect":"The music makes me relax feeling.","better":"The music helps me relax.","why":"This is the natural verb pattern."},{"incorrect":"I like music which have good melody.","better":"I like music that has a good melody.","why":"Music is singular here, so use has."}]$$::jsonb
  ),
  (
    'part-1-music',
    2,
    $$Did you listen to music more when you were younger?$$,
    $$Compare the past with now using one example.$$,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$Yes, I think I listened to music more when I was a teenager. I often followed popular singers and played music after school. Now I still like music, but I usually listen to it in the background while doing other things.$$,
    $$Yes, I probably listened to music more actively when I was younger. I used to follow new songs, share playlists with friends, and pay attention to singers. These days, music is still part of my life, but it is more like background company when I am commuting or working.$$,
    $$Definitely. When I was younger, music felt more central to my social life. My friends and I would recommend songs to each other, learn lyrics, and talk about singers we liked. Now I still enjoy music, but I use it in a more practical way, almost as background atmosphere while I cook, travel, or focus.$$,
    $$[{"phrase":"listen more actively","meaning":"pay more attention to music","example":"I listened more actively when I was younger."},{"phrase":"share playlists","meaning":"send lists of songs to others","example":"We used to share playlists."},{"phrase":"background company","meaning":"something pleasant playing while doing other tasks","example":"Music is background company when I work."},{"phrase":"background atmosphere","meaning":"sound that creates a mood","example":"Soft music creates background atmosphere."}]$$::jsonb,
    $$[{"insteadOf":"popular singer","try":["favourite artist","well-known singer","band"],"meaning":"a musician or music group","example":"I followed my favourite artist online.","context":"music artists"},{"insteadOf":"music friend","try":["share playlists","recommend songs","talk about lyrics"],"meaning":"activities connected to music and friends","example":"We recommended songs to each other.","context":"sharing music"},{"insteadOf":"past and now","try":["when I was younger","these days","nowadays"],"meaning":"time comparison phrases","example":"These days, I listen less actively.","context":"time comparison"}]$$::jsonb,
    $$[{"pattern":"I used to ___, but now ___.","example":"I used to follow new songs, but now I listen casually.","suitableUse":"Comparing past and present."},{"pattern":"When I was younger, ___ felt more ___.","example":"When I was younger, music felt more important.","suitableUse":"Explaining a past feeling."},{"pattern":"These days, ___ is more like ___.","example":"These days, music is more like background company.","suitableUse":"Describing current use."}]$$::jsonb,
    $$[{"incorrect":"When I young, I listened music.","better":"When I was young, I listened to music.","why":"Use was and listen to."},{"incorrect":"I more liked music before.","better":"I liked music more before. / I listened to music more before.","why":"Place more after the verb phrase."},{"incorrect":"Now music is background accompany.","better":"Now music is background company.","why":"Company is the noun meaning something that keeps you company."}]$$::jsonb
  ),
  (
    'part-2-useful-skill-you-learned',
    1,
    $$Describe a useful skill you learned.$$,
    null::text,
    $$["what the skill is","when and how you learned it","how often you use it","and explain why it is useful"]$$::jsonb,
    $$["Choose a practical skill you can explain with a short story.","Mention the learning process, not only the final result.","Explain one real situation where the skill helped you."]$$::jsonb,
    $$["Introduction","Learning process","A moment of difficulty","How you use it now","Why it is useful"]$$::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$A useful skill I learned is basic cooking. I learned it when I moved away from home for study. At first, I could only make very simple meals, and sometimes the food tasted strange. I watched short videos and asked my mother for advice. After a few months, I could cook noodles, soup, and simple vegetable dishes. I use this skill several times a week now. It is useful because it saves money and helps me eat more healthily. I am still not an excellent cook, but I feel more independent because I can take care of myself.$$,
    $$A useful skill I learned is cooking simple home-style meals. I started learning it when I first lived away from my family. At the beginning, I made a lot of mistakes, like adding too much salt or overcooking vegetables. I learned gradually by watching videos, calling my mother, and repeating the same dishes until they tasted better. Now I cook several times a week, especially when I am busy and do not want to rely on takeaway. It is useful not only because it saves money, but also because it gives me more control over what I eat. I would not say I am talented, but the skill has made daily life much easier.$$,
    $$One useful skill I have learned is how to cook practical everyday meals. I picked it up after moving away from home, when I realised that eating out all the time was expensive and not very healthy. My first attempts were honestly quite bad: the rice was sometimes too dry, and I had no idea how to season vegetables properly. Instead of trying complicated recipes, I focused on a few repeatable dishes and improved them slowly. These days, I can make a quick soup, stir-fried vegetables, or a simple rice bowl without much stress. The skill is useful because it gives me independence. More importantly, it turns a basic daily need into something I can manage calmly rather than avoid.$$,
    $$[{"phrase":"pick up a skill","meaning":"learn a skill gradually","example":"I picked up cooking after moving away from home."},{"phrase":"repeatable dishes","meaning":"meals you can make again easily","example":"I focused on a few repeatable dishes."},{"phrase":"rely on takeaway","meaning":"depend on bought prepared food","example":"I do not want to rely on takeaway."},{"phrase":"gives me independence","meaning":"helps me manage life by myself","example":"Cooking gives me independence."}]$$::jsonb,
    $$[{"insteadOf":"learn cooking","try":["pick up cooking","learn basic cooking","develop cooking skills"],"meaning":"learn how to prepare food","example":"I picked up basic cooking at university.","context":"Use for practical skills."},{"insteadOf":"food outside","try":["takeaway","restaurant meals","eating out"],"meaning":"food bought outside the home","example":"Eating out every day is expensive.","context":"Use when comparing cooking and buying food."},{"insteadOf":"do it many times","try":["repeat","practise regularly","build a routine"],"meaning":"use repetition to improve","example":"I improved by repeating simple dishes.","context":"Use for learning processes."}]$$::jsonb,
    $$[{"pattern":"I started learning it when ___.","example":"I started learning it when I moved away from home.","suitableUse":"Explaining background."},{"pattern":"At the beginning, I ___, but gradually ___.","example":"At the beginning, I made mistakes, but gradually I improved.","suitableUse":"Showing development."},{"pattern":"It is useful not only because ___, but also because ___.","example":"It is useful not only because it saves money, but also because it keeps me healthy.","suitableUse":"Explaining two benefits."}]$$::jsonb,
    $$[{"incorrect":"I learned cook when I left home.","better":"I learned to cook when I left home.","why":"Use learn to + verb."},{"incorrect":"I made many mistakes like too much salty.","better":"I made mistakes, like adding too much salt.","why":"Use salt as the noun and describe the action."},{"incorrect":"It lets me independent.","better":"It makes me more independent.","why":"Use make + object + adjective."}]$$::jsonb
  ),
  (
    'part-2-place-you-enjoy-visiting',
    1,
    $$Describe a place you enjoy visiting.$$,
    null::text,
    $$["where the place is","what you do there","who you usually go with","and explain why you enjoy visiting it"]$$::jsonb,
    $$["Choose a real place you know well.","Use sensory details such as sound, view, or atmosphere.","Explain why the place suits your mood or routine."]$$::jsonb,
    $$["Introduction","Location and atmosphere","Activities there","Who you go with","Personal meaning"]$$::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$A place I enjoy visiting is a small park near my home. It is not very famous, but it is peaceful. I usually go there in the evening to walk or sit on a bench. Sometimes I go alone, and sometimes I go with a friend. There are many trees and a small path around the park. I enjoy visiting it because it helps me relax after a busy day. It is also close to my home, so I do not need to plan much. For me, it is a simple but comfortable place.$$,
    $$A place I enjoy visiting is a small neighbourhood park about ten minutes from my home. It is not a tourist attraction, but that is exactly why I like it. In the evening, people walk their dogs, children ride bicycles, and older people sit under the trees. I usually go there alone when I need a break, although I sometimes walk there with a friend. What I enjoy most is the calm atmosphere. After a day of studying or working indoors, the park gives me a bit of fresh air and helps me reset my mood.$$,
    $$One place I really enjoy visiting is a quiet neighbourhood park within walking distance of my home. It is a very ordinary place at first glance, with a few tree-lined paths, benches, and a small open area where children play. But I find it comforting because it feels separate from the noise of daily life. I often go there in the early evening, either alone or with a close friend, and just walk slowly without any particular plan. What makes it special is not the scenery itself, but the routine it gives me. It is the place where I can slow down, breathe properly, and feel that the day has ended gently.$$,
    $$[{"phrase":"within walking distance","meaning":"close enough to walk to","example":"The park is within walking distance of my home."},{"phrase":"reset my mood","meaning":"feel calm again","example":"A walk helps me reset my mood."},{"phrase":"at first glance","meaning":"when you first see it","example":"At first glance, it looks ordinary."},{"phrase":"slow down","meaning":"become calmer and less rushed","example":"The park helps me slow down."}]$$::jsonb,
    $$[{"insteadOf":"near my home","try":["close to my home","within walking distance","in my neighbourhood"],"meaning":"near where you live","example":"It is within walking distance of my home.","context":"Use for local places."},{"insteadOf":"quiet feeling","try":["calm atmosphere","peaceful mood","relaxed environment"],"meaning":"a place that feels restful","example":"I enjoy the calm atmosphere.","context":"Use for parks, cafes, libraries."},{"insteadOf":"make me relax","try":["helps me unwind","helps me reset","clears my mind"],"meaning":"helps reduce stress","example":"The park helps me unwind.","context":"Use for places you enjoy."}]$$::jsonb,
    $$[{"pattern":"It is not ___, but that is why ___.","example":"It is not famous, but that is why I like it.","suitableUse":"Explaining a modest place."},{"pattern":"What I enjoy most is ___.","example":"What I enjoy most is the calm atmosphere.","suitableUse":"Highlighting a reason."},{"pattern":"It is the place where I can ___.","example":"It is the place where I can slow down.","suitableUse":"Ending with personal meaning."}]$$::jsonb,
    $$[{"incorrect":"I go there for relax.","better":"I go there to relax.","why":"Use to + verb for purpose."},{"incorrect":"The park is very peace.","better":"The park is very peaceful.","why":"Use peaceful as the adjective."},{"incorrect":"It makes my mood good.","better":"It improves my mood. / It helps me reset my mood.","why":"These phrases sound more natural."}]$$::jsonb
  ),
  (
    'part-2-person-who-helped-you',
    1,
    $$Describe a person who helped you.$$,
    null::text,
    $$["who this person is","what problem you had","how this person helped you","and explain how you felt about the help"]$$::jsonb,
    $$["Choose a specific situation, not a general description.","Explain what the person actually did.","Mention how the help changed your feelings or actions."]$$::jsonb,
    $$["Introduction","The problem","What the person did","Result","Reflection"]$$::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$A person who helped me was one of my classmates. Last year, I had trouble preparing for a group presentation because I was nervous and did not know how to organise my part. My classmate helped me make a simple outline and practised with me after class. He also gave me honest advice about speaking more slowly. Because of his help, I felt less worried and did better in the presentation. I was grateful because he was busy too, but he still spent time helping me.$$,
    $$A person who helped me was a classmate from one of my university courses. We had to give a group presentation, and I was struggling with my section because my ideas were not organised. He sat with me after class and helped me turn my notes into a clear outline. He also listened while I practised and pointed out where I was speaking too quickly. His help made a big difference because I went into the presentation feeling prepared rather than panicked. I appreciated it because he did not take over the task; he helped me improve it myself.$$,
    $$One person who helped me in a meaningful way was a classmate I worked with during a university presentation. At the time, I had plenty of information, but I could not shape it into a clear argument, and I was getting quite anxious. Instead of simply correcting my slides, he asked me questions about what I wanted the audience to understand. That helped me rebuild my section around two main points. He then listened to me practise and gave specific feedback on pacing and transitions. What I valued most was that he made the task feel manageable without making me feel incapable. After that experience, I became more confident about asking for feedback.$$,
    $$[{"phrase":"make a clear outline","meaning":"organise main points","example":"He helped me make a clear outline."},{"phrase":"speak too quickly","meaning":"talk faster than listeners can follow","example":"I was speaking too quickly."},{"phrase":"make a big difference","meaning":"have an important positive effect","example":"His advice made a big difference."},{"phrase":"feel manageable","meaning":"feel possible to handle","example":"He made the task feel manageable."}]$$::jsonb,
    $$[{"insteadOf":"helped me a lot","try":["gave me practical support","made a big difference","guided me patiently"],"meaning":"describe real help more clearly","example":"Her advice made a big difference.","context":"Use when describing support."},{"insteadOf":"very nervous","try":["anxious","panicked","under pressure"],"meaning":"worried or stressed","example":"I felt panicked before the presentation.","context":"Use for difficult situations."},{"insteadOf":"gave advice","try":["gave specific feedback","pointed out a problem","suggested an improvement"],"meaning":"offered useful comments","example":"He gave specific feedback on pacing.","context":"Use for study or work help."}]$$::jsonb,
    $$[{"pattern":"I was struggling with ___ because ___.","example":"I was struggling with my presentation because my ideas were unclear.","suitableUse":"Explaining the problem."},{"pattern":"Instead of ___, this person ___.","example":"Instead of doing it for me, he helped me organise my ideas.","suitableUse":"Showing how help was valuable."},{"pattern":"What I valued most was ___.","example":"What I valued most was his patience.","suitableUse":"Adding reflection."}]$$::jsonb,
    $$[{"incorrect":"He helped me to made outline.","better":"He helped me make an outline.","why":"Use help someone do something."},{"incorrect":"I was nervous for presentation.","better":"I was nervous about the presentation.","why":"Use nervous about."},{"incorrect":"He gave me many advices.","better":"He gave me a lot of advice.","why":"Advice is uncountable."}]$$::jsonb
  ),
  (
    'part-2-piece-of-technology-you-use',
    1,
    $$Describe a piece of technology you use often.$$,
    null::text,
    $$["what it is","when you started using it","what you use it for","and explain why it is important to you"]$$::jsonb,
    $$["Choose one device or app, not technology in general.","Mention specific daily uses.","Include one downside or limitation for a more natural answer."]$$::jsonb,
    $$["Introduction","When you got it","Main uses","Why it matters","A balanced comment"]$$::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$A piece of technology I use often is my smartphone. I started using my current phone about two years ago. I use it for messages, maps, photos, and online banking. It is important because many daily tasks are connected to it. For example, I use it to check transport routes and pay for things. Sometimes it distracts me, especially at night, but overall it makes my life much more convenient.$$,
    $$A piece of technology I use every day is my smartphone. I bought my current one about two years ago, and it has become almost like a small personal assistant. I use it for practical things such as navigation, banking, reminders, and staying in touch with family. It is important because it saves time and helps me handle small tasks quickly. The only downside is that it can be distracting, so I try not to keep it next to me when I need to focus.$$,
    $$One piece of technology I rely on heavily is my smartphone. I started using my current phone a couple of years ago, and over time it has become much more than a communication tool. I use it to navigate unfamiliar places, manage payments, take quick notes, store tickets, and contact people when plans change. What makes it important is not one dramatic feature, but the way it quietly supports many small parts of daily life. Of course, that convenience comes with a cost: if I am not careful, I can waste time checking it out of habit. So I try to use it as a tool rather than a constant source of entertainment.$$,
    $$[{"phrase":"personal assistant","meaning":"something that helps with many daily tasks","example":"My phone is like a small personal assistant."},{"phrase":"stay in touch with","meaning":"keep communicating with someone","example":"I use it to stay in touch with family."},{"phrase":"rely on heavily","meaning":"depend on a lot","example":"I rely on my phone heavily."},{"phrase":"out of habit","meaning":"without really thinking","example":"I check my phone out of habit."}]$$::jsonb,
    $$[{"insteadOf":"use it a lot","try":["rely on it","use it every day","depend on it"],"meaning":"need or use something often","example":"I rely on my phone for maps.","context":"Use for important technology."},{"insteadOf":"many functions","try":["features","daily tools","practical uses"],"meaning":"things a device can do","example":"The phone has many practical uses.","context":"Use when describing devices."},{"insteadOf":"bad side","try":["downside","drawback","limitation"],"meaning":"negative aspect","example":"The main downside is distraction.","context":"Use for balanced answers."}]$$::jsonb,
    $$[{"pattern":"It has become almost like ___.","example":"It has become almost like a personal assistant.","suitableUse":"Describing importance."},{"pattern":"What makes it important is not ___, but ___.","example":"What makes it important is not one feature, but how it supports daily life.","suitableUse":"Giving a nuanced reason."},{"pattern":"The only downside is that ___.","example":"The only downside is that it can distract me.","suitableUse":"Adding balance."}]$$::jsonb,
    $$[{"incorrect":"I use it to contact with people.","better":"I use it to contact people. / I use it to keep in touch with people.","why":"Contact does not need with."},{"incorrect":"It is very convenience.","better":"It is very convenient.","why":"Use convenient as the adjective."},{"incorrect":"I cannot leave it because it has many useful.","better":"I rely on it because it has many useful features.","why":"Useful needs a noun after it."}]$$::jsonb
  ),
  (
    'part-2-book-or-film-you-enjoyed',
    1,
    $$Describe a book or film you enjoyed.$$,
    null::text,
    $$["what it was","when you read or watched it","what it was about","and explain why you enjoyed it"]$$::jsonb,
    $$["Choose a story you can summarise simply.","Avoid retelling the whole plot.","Focus on one theme, character, or feeling."]$$::jsonb,
    $$["Introduction","When you watched or read it","Short summary","What you liked","Why it stayed with you"]$$::jsonb,
    null::text,
    null::text,
    null::text,
    null::text,
    $$A film I enjoyed was an animated film about a young person following a dream. I watched it with my family a few years ago. The story was simple, but it was emotional and easy to understand. I liked the music and the message that family and personal goals can both be important. I enjoyed it because it made me feel warm and reminded me to be patient with people I love.$$,
    $$A film I enjoyed was an animated movie about a young person trying to follow a dream while also understanding family expectations. I watched it a few years ago with my family, and I remember it clearly because the story was touching without being too heavy. The music was memorable, but what I liked most was the way the film showed conflict inside a family. It made the characters feel real rather than perfect. I enjoyed it because it left me with a warm feeling and made me think about how people express love in different ways.$$,
    $$One film I really enjoyed was an animated story about ambition, family, and memory. I watched it at home with my family, and although I expected something light, it turned out to be surprisingly moving. The plot follows a young character who wants to pursue a personal dream, but gradually learns more about his family's past. What impressed me was that the film did not present family as simply supportive or restrictive; it showed how love can sometimes be expressed in confusing ways. I also loved the music, because it made the emotional moments feel sincere rather than forced. The film stayed with me because it was entertaining, but also quietly reflective.$$,
    $$[{"phrase":"touching without being too heavy","meaning":"emotional but not depressing","example":"The story was touching without being too heavy."},{"phrase":"family expectations","meaning":"what family members hope you will do","example":"The film explores family expectations."},{"phrase":"surprisingly moving","meaning":"more emotional than expected","example":"The ending was surprisingly moving."},{"phrase":"feel sincere rather than forced","meaning":"feel real, not artificial","example":"The music made the scene feel sincere rather than forced."}]$$::jsonb,
    $$[{"insteadOf":"good story","try":["touching story","memorable plot","well-told story"],"meaning":"a story that has impact","example":"It has a touching story.","context":"Use for books or films."},{"insteadOf":"main person","try":["main character","central character","protagonist"],"meaning":"the key person in a story","example":"The main character changes a lot.","context":"Use for stories."},{"insteadOf":"made me think","try":["left me thinking","made me reflect","stayed with me"],"meaning":"continued to affect your thoughts","example":"The film stayed with me.","context":"Use for emotional reactions."}]$$::jsonb,
    $$[{"pattern":"What I liked most was the way ___.","example":"What I liked most was the way the film showed family conflict.","suitableUse":"Explaining a specific strength."},{"pattern":"Although I expected ___, it turned out to be ___.","example":"Although I expected something light, it turned out to be moving.","suitableUse":"Adding surprise."},{"pattern":"It stayed with me because ___.","example":"It stayed with me because it was both entertaining and thoughtful.","suitableUse":"Ending with reflection."}]$$::jsonb,
    $$[{"incorrect":"The film is about a person chase dream.","better":"The film is about a person chasing a dream.","why":"Use about + noun phrase or verb-ing."},{"incorrect":"I watched it before few years.","better":"I watched it a few years ago.","why":"Use ago for past time."},{"incorrect":"It made me very moved feeling.","better":"It moved me. / It made me feel moved.","why":"Use moved as an adjective or move as a verb."}]$$::jsonb
  ),
  (
    'part-3-public-transport-and-cities',
    1,
    $$Why do some people prefer driving instead of using public transport?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Many people prefer driving because it gives them more control and privacy.$$,
    $$Public transport can be crowded or indirect, while driving allows people to choose their route, leave when they want, and carry things more easily.$$,
    $$For example, parents with young children may find driving easier because they can bring bags, strollers, and other items without changing buses or trains.$$,
    $$However, this preference depends on the city. In places with fast and reliable trains, driving may be less attractive.$$,
    $$Some people prefer driving because it is more flexible. They can leave at any time and go directly to the place they want. Public transport can be crowded, and sometimes people need to wait or change lines. Driving is also easier when carrying many things or travelling with children.$$,
    $$Many people choose driving because it gives them a stronger sense of control. They do not have to follow a fixed timetable, and they can travel directly from door to door. This is especially useful for families, people carrying heavy bags, or those living in areas with poor transport links. Still, driving is not always faster if traffic and parking are serious problems.$$,
    $$I think the main reason is control. Driving allows people to decide when to leave, where to stop, and how much luggage to carry, which public transport does not always allow. It can also feel more private, especially after a long day when people do not want to stand in a crowded train. That said, the preference is very context-dependent. In a city with efficient metro lines and expensive parking, public transport may actually be the easier choice.$$,
    $$[{"phrase":"a stronger sense of control","meaning":"feeling able to decide more things","example":"Driving gives people a stronger sense of control."},{"phrase":"door to door","meaning":"directly from one place to another","example":"A car can take you door to door."},{"phrase":"poor transport links","meaning":"weak public transport connections","example":"Rural areas often have poor transport links."},{"phrase":"context-dependent","meaning":"changing according to the situation","example":"The best option is context-dependent."}]$$::jsonb,
    $$[{"insteadOf":"more free","try":["more flexible","more convenient","more independent"],"meaning":"having more choice","example":"Driving is more flexible for families.","context":"Use when comparing transport."},{"insteadOf":"change bus","try":["transfer","change lines","make connections"],"meaning":"switch from one route to another","example":"Some commuters need to change lines twice.","context":"Use for public transport routes."},{"insteadOf":"many cars problem","try":["traffic congestion","parking pressure","road delays"],"meaning":"transport problems caused by cars","example":"Traffic congestion makes driving stressful.","context":"Use for city transport discussions."}]$$::jsonb,
    $$[{"pattern":"The main reason is ___.","example":"The main reason is flexibility.","suitableUse":"Starting a Part 3 answer directly."},{"pattern":"This is especially useful for ___.","example":"This is especially useful for families with young children.","suitableUse":"Adding specific groups."},{"pattern":"That said, the preference depends on ___.","example":"That said, the preference depends on the city.","suitableUse":"Adding qualification."}]$$::jsonb,
    $$[{"incorrect":"Driving is more freedom.","better":"Driving gives people more freedom.","why":"Freedom is a noun; use gives people more freedom."},{"incorrect":"People can arrive directly to home.","better":"People can travel directly home. / People can go directly to their destination.","why":"Use directly with travel or go."},{"incorrect":"Public transport has many crowded.","better":"Public transport is often crowded.","why":"Crowded is an adjective."}]$$::jsonb
  ),
  (
    'part-3-public-transport-and-cities',
    2,
    $$How can cities encourage more people to use public transport?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Cities can improve reliability, comfort, and convenience.$$,
    $$People are more likely to use public transport if it is frequent, affordable, clean, and connected to where they actually need to go.$$,
    $$For instance, dedicated bus lanes can make buses faster, while simple payment systems can reduce inconvenience for occasional users.$$,
    $$At the same time, cities may need to manage parking and road space so that driving is not always the easiest option.$$,
    $$Cities can encourage public transport by making it cheaper and more reliable. If buses and trains come often, people will not need to wait for a long time. Clean stations and safe routes are also important. Some cities can also reduce parking spaces in busy areas.$$,
    $$Cities need to make public transport feel like a practical choice, not a sacrifice. That means services should be frequent, punctual, affordable, and easy to understand. For example, clear route information and simple payment systems can make a big difference for new users. Governments can also improve bus lanes or train connections so that public transport is not much slower than driving.$$,
    $$To encourage public transport use, cities have to improve both the service itself and the way people experience it. A cheap ticket is not enough if the bus is unreliable or the station feels unsafe. Frequent services, clean vehicles, clear signs, and integrated payment systems all reduce the small frustrations that push people back to cars. At the same time, city planners may need to limit parking in crowded centres, so public transport becomes not only responsible but genuinely convenient.$$,
    $$[{"phrase":"a practical choice, not a sacrifice","meaning":"an option that feels useful, not difficult","example":"Public transport should be a practical choice, not a sacrifice."},{"phrase":"simple payment systems","meaning":"easy ways to pay","example":"Simple payment systems help new users."},{"phrase":"integrated payment systems","meaning":"one payment method across transport types","example":"Integrated payment systems make transfers easier."},{"phrase":"small frustrations","meaning":"minor problems that become annoying","example":"Small frustrations push people back to cars."}]$$::jsonb,
    $$[{"insteadOf":"come many times","try":["run frequently","operate regularly","come often"],"meaning":"arrive often","example":"Buses need to run frequently.","context":"service frequency"},{"insteadOf":"not late","try":["punctual","reliable","on schedule"],"meaning":"arriving as expected","example":"A reliable service attracts commuters.","context":"Use for transport quality."},{"insteadOf":"easy pay","try":["simple payment system","contactless payment","integrated ticketing"],"meaning":"convenient payment method","example":"Integrated ticketing reduces hassle.","context":"Use for public transport improvements."}]$$::jsonb,
    $$[{"pattern":"Cities need to make ___ feel like ___.","example":"Cities need to make buses feel like a practical choice.","suitableUse":"Discussing policy goals."},{"pattern":"A ___ is not enough if ___.","example":"A cheap ticket is not enough if the train is unreliable.","suitableUse":"Explaining limits."},{"pattern":"At the same time, planners may need to ___.","example":"At the same time, planners may need to limit parking.","suitableUse":"Adding another measure."}]$$::jsonb,
    $$[{"incorrect":"Government should make bus more convenience.","better":"The government should make buses more convenient.","why":"Use convenient as an adjective and plural buses."},{"incorrect":"People will use if cheap.","better":"People will use it if it is cheap.","why":"Include object and subject."},{"incorrect":"Public transport should more fast.","better":"Public transport should be faster.","why":"Use be + comparative adjective."}]$$::jsonb
  ),
  (
    'part-3-sports-and-health',
    1,
    $$Why do some people find it difficult to exercise regularly?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Many people struggle because they are busy, tired, or lack motivation.$$,
    $$Regular exercise requires time and routine, but modern work and study schedules can make people feel too exhausted to start.$$,
    $$For example, someone who commutes for a long time may prefer resting at home instead of going to a gym in the evening.$$,
    $$Still, the problem is not only time. Some people also feel embarrassed or do not know what type of exercise suits them.$$,
    $$Some people find exercise difficult because they are busy with work or study. After a long day, they may feel too tired to go to the gym. Others do not enjoy sports, so they lose motivation quickly. It is easier to continue when exercise becomes part of a routine.$$,
    $$I think the main difficulty is building a routine. Many people know exercise is good for them, but they feel tired after work or they do not know where to start. Gyms can also feel intimidating for beginners. If exercise feels like another stressful task, people are less likely to continue it for long.$$,
    $$There are several practical reasons, but I think the biggest one is that exercise competes with everything else in daily life. After work, commuting, study, and family responsibilities, people may not have much mental energy left. Another issue is confidence. If someone has not exercised for years, a gym or sports club can feel intimidating. So the solution is not just telling people to be disciplined; exercise has to feel accessible and realistic.$$,
    $$[{"phrase":"building a routine","meaning":"creating a regular habit","example":"The hard part is building a routine."},{"phrase":"feel intimidating","meaning":"feel scary or difficult to approach","example":"Gyms can feel intimidating for beginners."},{"phrase":"mental energy","meaning":"the ability to focus or motivate yourself","example":"I have little mental energy after work."},{"phrase":"accessible and realistic","meaning":"easy enough to start and continue","example":"Exercise should feel accessible and realistic."}]$$::jsonb,
    $$[{"insteadOf":"no time","try":["busy schedule","lack of time","limited free time"],"meaning":"not having enough time","example":"A busy schedule makes exercise difficult.","context":"Use for lifestyle barriers."},{"insteadOf":"no power","try":["lack of energy","feel exhausted","low motivation"],"meaning":"not feeling ready to act","example":"Low motivation is a common barrier.","context":"Use for exercise habits."},{"insteadOf":"scary gym","try":["intimidating gym","unfamiliar environment","beginner anxiety"],"meaning":"feeling nervous in a sport setting","example":"An unfamiliar gym can be intimidating.","context":"Use for new exercisers."}]$$::jsonb,
    $$[{"pattern":"The main difficulty is ___.","example":"The main difficulty is building a routine.","suitableUse":"Direct Part 3 answer."},{"pattern":"If ___ feels like ___, people are less likely to ___.","example":"If exercise feels like a chore, people are less likely to continue.","suitableUse":"Explaining cause and effect."},{"pattern":"The solution is not just ___; it also needs to ___.","example":"The solution is not just discipline; it also needs to be realistic.","suitableUse":"Adding nuance."}]$$::jsonb,
    $$[{"incorrect":"People are hard to exercise.","better":"It is hard for people to exercise.","why":"Use it is hard for someone to do something."},{"incorrect":"They lack exercise motivation regularly.","better":"They lack motivation to exercise regularly.","why":"Use motivation to + verb."},{"incorrect":"Gym is fear for beginners.","better":"The gym can feel intimidating for beginners.","why":"Intimidating is the natural adjective here."}]$$::jsonb
  ),
  (
    'part-3-sports-and-health',
    2,
    $$Should governments encourage people to do more sport?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Yes, because regular physical activity can reduce health problems and improve quality of life.$$,
    $$Governments can support this by building safe public spaces, funding sports facilities, and encouraging schools to include physical activity.$$,
    $$For example, free outdoor exercise areas in parks can help people who cannot afford private gyms.$$,
    $$However, encouragement should not become pressure. People need options that suit different ages, abilities, and schedules.$$,
    $$Yes, governments should encourage sport because it can improve public health. If people exercise more, they may have fewer health problems. Governments can build parks, sports centres, and safe cycling paths. They can also encourage schools to give students enough time for physical activities.$$,
    $$Yes, I think governments have a role in encouraging sport, mainly because public health affects everyone. They can provide affordable facilities, safe parks, and school programmes that help people build active habits from a young age. However, the aim should be to make exercise easier, not to force everyone into competitive sports.$$,
    $$I do think governments should encourage people to be more active, but the approach matters. Instead of simply telling citizens to exercise, they should remove practical barriers by providing safe walking paths, public sports facilities, and affordable community classes. This can reduce long-term pressure on healthcare systems and improve everyday wellbeing. At the same time, sport should be promoted as something flexible and inclusive, because not everyone enjoys competition or has the same physical ability.$$,
    $$[{"phrase":"public health affects everyone","meaning":"community health has wide effects","example":"Public health affects everyone."},{"phrase":"remove practical barriers","meaning":"make obstacles easier to overcome","example":"Cities should remove practical barriers to exercise."},{"phrase":"long-term pressure on healthcare systems","meaning":"future demand on hospitals and health services","example":"Exercise can reduce long-term pressure on healthcare systems."},{"phrase":"flexible and inclusive","meaning":"suitable for many different people","example":"Sport should be flexible and inclusive."}]$$::jsonb,
    $$[{"insteadOf":"make people sport","try":["encourage physical activity","promote sport","support active lifestyles"],"meaning":"help people exercise more","example":"Governments can promote active lifestyles.","context":"Use for policy."},{"insteadOf":"sport places","try":["sports facilities","public exercise areas","safe parks"],"meaning":"places for exercise","example":"Affordable sports facilities are important.","context":"Use for public services."},{"insteadOf":"health money problem","try":["healthcare costs","pressure on hospitals","public health burden"],"meaning":"costs or demand connected to health","example":"Exercise can reduce healthcare costs.","context":"Use for public health."}]$$::jsonb,
    $$[{"pattern":"Governments have a role in ___ because ___.","example":"Governments have a role in promoting sport because health affects society.","suitableUse":"Discussing responsibility."},{"pattern":"Instead of simply ___, they should ___.","example":"Instead of simply advising people, they should provide facilities.","suitableUse":"Suggesting practical policy."},{"pattern":"At the same time, ___ should be ___.","example":"At the same time, sport should be inclusive.","suitableUse":"Adding balance."}]$$::jsonb,
    $$[{"incorrect":"Government should let people do more sport.","better":"The government should encourage people to do more sport.","why":"Encourage is more natural than let here."},{"incorrect":"Sport can reduce healthy problem.","better":"Sport can reduce health problems.","why":"Use health as a noun modifier."},{"incorrect":"Not everyone are same ability.","better":"Not everyone has the same ability.","why":"Use everyone has."}]$$::jsonb
  ),
  (
    'part-3-tourism-and-local-culture',
    1,
    $$How can tourism affect local culture?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Tourism can both protect and change local culture.$$,
    $$It can bring money and attention to local traditions, but it can also turn culture into something performed mainly for visitors.$$,
    $$For example, traditional crafts may survive because tourists buy them, but the designs may become simplified to suit tourist tastes.$$,
    $$The impact depends on whether local communities have control over how their culture is presented.$$,
    $$Tourism can affect local culture in both good and bad ways. It can help local people earn money and share their traditions. However, some traditions may become commercial if they are only made for tourists. Local people need to protect the real meaning of their culture.$$,
    $$Tourism can support local culture by creating demand for traditional food, crafts, and festivals. This can help communities keep traditions alive. At the same time, culture may become commercialised if it is changed too much to please visitors. So tourism is positive only when local people have a real say in how their culture is presented.$$,
    $$Tourism can be a powerful way to keep local culture visible, but it can also reshape that culture. On the positive side, visitors may create income for craftspeople, performers, and local guides, which gives traditions practical value in modern life. On the negative side, cultural activities can become staged or simplified if they are designed mainly for tourists. I think the key issue is control: local communities should benefit from tourism without feeling forced to package their identity for outside expectations.$$,
    $$[{"phrase":"keep traditions alive","meaning":"help traditions continue","example":"Tourism can keep traditions alive."},{"phrase":"become commercialised","meaning":"become too focused on selling","example":"Some festivals become commercialised."},{"phrase":"have a real say","meaning":"have genuine influence","example":"Local people should have a real say."},{"phrase":"package their identity","meaning":"present culture in a simplified saleable way","example":"Communities should not have to package their identity."}]$$::jsonb,
    $$[{"insteadOf":"old culture","try":["local traditions","cultural heritage","traditional practices"],"meaning":"customs from a community","example":"Tourism can support cultural heritage.","context":"Use for culture topics."},{"insteadOf":"make money","try":["create income","support local businesses","bring economic benefits"],"meaning":"help people earn money","example":"Tourism creates income for local guides.","context":"Use for tourism benefits."},{"insteadOf":"fake culture","try":["staged culture","commercialised culture","simplified performance"],"meaning":"culture changed for visitors","example":"Some shows feel like staged culture.","context":"Use for tourism criticism."}]$$::jsonb,
    $$[{"pattern":"Tourism can both ___ and ___.","example":"Tourism can both protect and change culture.","suitableUse":"Balanced Part 3 answer."},{"pattern":"On the positive side, ___. On the negative side, ___.","example":"On the positive side, it creates income. On the negative side, it can commercialise traditions.","suitableUse":"Organising pros and cons."},{"pattern":"The key issue is ___.","example":"The key issue is whether local people have control.","suitableUse":"Adding a main insight."}]$$::jsonb,
    $$[{"incorrect":"Tourism can make culture disappear or popular.","better":"Tourism can either weaken culture or make it more visible.","why":"Use a clearer parallel structure."},{"incorrect":"Local people should have say.","better":"Local people should have a say.","why":"Use have a say."},{"incorrect":"Culture becomes business too much.","better":"Culture can become too commercialised.","why":"Commercialised is a precise adjective."}]$$::jsonb
  ),
  (
    'part-3-tourism-and-local-culture',
    2,
    $$Should visitors learn about local customs before travelling?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Yes, because it helps visitors behave respectfully and avoid misunderstandings.$$,
    $$Learning basic customs can make travel smoother, especially in places where behaviour around clothing, greetings, or public spaces is different.$$,
    $$For example, knowing how to greet people politely or dress appropriately at religious sites can prevent accidental offence.$$,
    $$Of course, visitors do not need to know everything, but they should show curiosity and humility.$$,
    $$Yes, visitors should learn some local customs before travelling. It helps them avoid rude behaviour and communicate better with local people. For example, they can learn how to greet people or what clothes are suitable in certain places. They do not need to know everything, but they should be respectful.$$,
    $$Yes, I think it is a good idea. Visitors do not have to study a culture deeply, but they should understand basic rules about greetings, clothing, and behaviour in public places. This shows respect and can prevent awkward situations. It also makes travel more meaningful because tourists can connect with local people more naturally.$$,
    $$I think visitors should learn at least the basics of local customs before they travel. This is not about becoming an expert, but about showing respect and avoiding careless mistakes. Something as simple as understanding how to greet people, how to behave at religious sites, or whether tipping is expected can make interactions smoother. It also changes the traveller's attitude: instead of treating the destination as a backdrop for photos, they become more aware that they are entering someone else's community.$$,
    $$[{"phrase":"avoid misunderstandings","meaning":"prevent confusion or offence","example":"Learning customs helps avoid misunderstandings."},{"phrase":"awkward situations","meaning":"uncomfortable social moments","example":"Basic knowledge can prevent awkward situations."},{"phrase":"at least the basics","meaning":"the most important simple points","example":"Visitors should learn at least the basics."},{"phrase":"someone else's community","meaning":"a place where other people live and belong","example":"Tourists are entering someone else's community."}]$$::jsonb,
    $$[{"insteadOf":"know culture","try":["learn local customs","understand basic etiquette","be aware of traditions"],"meaning":"know how to behave respectfully","example":"Tourists should understand basic etiquette.","context":"Use for travel behaviour."},{"insteadOf":"bad behaviour","try":["rude behaviour","careless mistake","accidental offence"],"meaning":"behaviour that may upset people","example":"A careless mistake can offend locals.","context":"Use for culture and manners."},{"insteadOf":"talk with local people","try":["interact with locals","connect with local people","communicate respectfully"],"meaning":"have contact with residents","example":"Visitors can interact with locals more naturally.","context":"Use for travel experience."}]$$::jsonb,
    $$[{"pattern":"This is not about ___, but about ___.","example":"This is not about knowing everything, but about showing respect.","suitableUse":"Clarifying your position."},{"pattern":"Something as simple as ___ can ___.","example":"Something as simple as learning a greeting can improve communication.","suitableUse":"Giving practical examples."},{"pattern":"Instead of treating ___ as ___, they ___.","example":"Instead of treating a city as a photo spot, they respect it as a community.","suitableUse":"Adding nuance."}]$$::jsonb,
    $$[{"incorrect":"Visitors should respect to local culture.","better":"Visitors should respect local culture.","why":"Respect does not need to."},{"incorrect":"They do not need know all customs.","better":"They do not need to know all customs.","why":"Use need to + verb."},{"incorrect":"It can avoid to offend people.","better":"It can help avoid offending people.","why":"Use avoid + verb-ing."}]$$::jsonb
  ),
  (
    'part-3-work-life-balance',
    1,
    $$Why is work-life balance important?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Work-life balance is important because people need time to recover and maintain relationships.$$,
    $$If work takes up too much time and energy, people may become stressed, less productive, and disconnected from family or friends.$$,
    $$For example, someone who works late every night may earn more in the short term but damage their health and personal life over time.$$,
    $$However, balance does not always mean equal hours. It means having enough control to meet both work and personal needs.$$,
    $$Work-life balance is important because people cannot work all the time. If they do, they may feel stressed and tired. They also need time for family, friends, exercise, and hobbies. A good balance can make people healthier and more productive at work.$$,
    $$Work-life balance matters because people need time to recover physically and mentally. If someone works too many hours, they may become less focused and more irritable, even if they are trying hard. Time with family, friends, or hobbies can help people return to work with more energy. So balance is good for both personal life and performance.$$,
    $$Work-life balance is important because it protects both wellbeing and long-term productivity. People can push themselves for a short period, but if work consistently takes over their evenings and weekends, stress starts to affect their health, relationships, and decision-making. I do not think balance means dividing time perfectly every day. It means having enough space to rest, maintain relationships, and feel that life is not only about meeting deadlines.$$,
    $$[{"phrase":"recover physically and mentally","meaning":"rest the body and mind","example":"People need time to recover physically and mentally."},{"phrase":"long-term productivity","meaning":"being productive over a long period","example":"Rest supports long-term productivity."},{"phrase":"takes over evenings and weekends","meaning":"uses personal time too much","example":"Work often takes over evenings and weekends."},{"phrase":"meeting deadlines","meaning":"finishing work by required dates","example":"Life should not only be about meeting deadlines."}]$$::jsonb,
    $$[{"insteadOf":"balance work and life","try":["work-life balance","balance work with personal life","manage work and rest"],"meaning":"having enough time for both work and life","example":"Work-life balance affects health.","context":"Use for work topics."},{"insteadOf":"tired brain","try":["mental fatigue","stress","lack of focus"],"meaning":"mental tiredness","example":"Mental fatigue affects performance.","context":"Use for health and productivity."},{"insteadOf":"family time","try":["personal time","time with loved ones","social life"],"meaning":"time outside work","example":"People need personal time.","context":"Use for balance."}]$$::jsonb,
    $$[{"pattern":"Balance matters because ___.","example":"Balance matters because people need time to recover.","suitableUse":"Directly answering why questions."},{"pattern":"If work consistently ___, then ___.","example":"If work consistently takes over evenings, stress increases.","suitableUse":"Cause-effect explanation."},{"pattern":"I do not think ___ means ___; it means ___.","example":"I do not think balance means equal hours; it means enough control.","suitableUse":"Adding nuance."}]$$::jsonb,
    $$[{"incorrect":"Work-life balance can make people more health.","better":"Work-life balance can make people healthier.","why":"Use healthier as the adjective."},{"incorrect":"People need rest their mind.","better":"People need to rest their minds.","why":"Use need to + verb."},{"incorrect":"Work occupy all time.","better":"Work takes up all their time.","why":"Takes up time is the natural phrase."}]$$::jsonb
  ),
  (
    'part-3-work-life-balance',
    2,
    $$Do you think flexible working is good for employees?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Yes, flexible working can help employees manage their time and responsibilities better.$$,
    $$It can reduce commuting stress and allow people to work when they are most focused, but it also requires self-discipline.$$,
    $$For example, a parent may start work earlier so they can pick up a child from school in the afternoon.$$,
    $$It is beneficial only when expectations are clear. Otherwise, flexibility can turn into always being available.$$,
    $$Yes, flexible working is good for many employees because they can manage their time better. They may avoid traffic and spend more time with family. However, some people may find it difficult to separate work and home life, especially if they work from home.$$,
    $$I think flexible working can be very helpful, especially for people with family responsibilities or long commutes. It allows employees to organise their day in a way that suits their energy and personal needs. However, it works best when managers set clear expectations, because otherwise employees may feel they have to answer messages at any time.$$,
    $$Flexible working can be good for employees, but only if it is managed properly. The obvious benefit is control: people can avoid rush-hour travel, handle family responsibilities, or work during their most productive hours. That can improve both morale and efficiency. The risk is that the boundary between work and private life becomes blurred. If a flexible job quietly turns into being available all evening, then it may create more stress rather than less.$$,
    $$[{"phrase":"long commutes","meaning":"travel that takes a lot of time","example":"Flexible work helps people with long commutes."},{"phrase":"clear expectations","meaning":"understanding what is required","example":"Managers should set clear expectations."},{"phrase":"being available all evening","meaning":"having to respond to work after hours","example":"Employees may feel they are available all evening."},{"phrase":"boundary becomes blurred","meaning":"the separation becomes unclear","example":"The boundary between work and home becomes blurred."}]$$::jsonb,
    $$[{"insteadOf":"free work time","try":["flexible working","flexible schedule","remote work"],"meaning":"work with adjustable time or place","example":"Flexible working can reduce commuting stress.","context":"Use for employment topics."},{"insteadOf":"answer anytime","try":["always available","constant communication","after-hours messages"],"meaning":"work contact outside normal hours","example":"After-hours messages can create stress.","context":"Use for flexible work drawbacks."},{"insteadOf":"good feeling","try":["morale","job satisfaction","motivation"],"meaning":"how positive employees feel","example":"Flexibility can improve morale.","context":"Use for work benefits."}]$$::jsonb,
    $$[{"pattern":"It works best when ___.","example":"It works best when expectations are clear.","suitableUse":"Giving conditions."},{"pattern":"The obvious benefit is ___.","example":"The obvious benefit is control.","suitableUse":"Introducing the main advantage."},{"pattern":"The risk is that ___.","example":"The risk is that work and home life become mixed.","suitableUse":"Adding a drawback."}]$$::jsonb,
    $$[{"incorrect":"Flexible work is benefit for employees.","better":"Flexible work is beneficial for employees.","why":"Use beneficial as the adjective."},{"incorrect":"They can balance family more easy.","better":"They can balance family responsibilities more easily.","why":"Use easily as an adverb."},{"incorrect":"Work and life become blur.","better":"Work and life become blurred.","why":"Use blurred as the adjective."}]$$::jsonb
  ),
  (
    'part-3-advertising-and-consumer-behaviour',
    1,
    $$How does advertising influence what people buy?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$Advertising influences people by shaping what they notice, remember, and trust.$$,
    $$It can make products look more attractive by connecting them with emotions, lifestyles, or social status.$$,
    $$For example, an advert for a sports drink may focus less on the drink itself and more on energy, confidence, and achievement.$$,
    $$However, advertising does not control everyone. People are still influenced by price, quality, reviews, and personal needs.$$,
    $$Advertising influences people because it makes products more visible and attractive. If people see the same product many times, they may remember it when shopping. Some adverts also create a feeling that a product is popular or high quality, even before people try it.$$,
    $$Advertising affects buying decisions by creating familiarity and desire. A product that appears often online or in public spaces can seem more trustworthy simply because people recognise it. Advertisements also connect products with emotions, such as confidence, beauty, or success. Still, consumers do not rely only on adverts; price and reviews also matter.$$,
    $$Advertising influences buying behaviour partly by shaping attention. People cannot compare every product carefully, so adverts help certain brands stand out. They often sell an image as much as the item itself, linking a product with confidence, status, or a desirable lifestyle. That said, advertising has limits. A strong advert may persuade someone to notice a product, but repeated bad reviews or a price that feels unreasonable can still stop the purchase.$$,
    $$[{"phrase":"creating familiarity and desire","meaning":"making something feel known and wanted","example":"Advertising creates familiarity and desire."},{"phrase":"shape attention","meaning":"influence what people notice","example":"Adverts shape attention."},{"phrase":"stand out","meaning":"be noticed more than others","example":"Good branding helps products stand out."},{"phrase":"sell an image","meaning":"promote a lifestyle or feeling, not just a product","example":"Some adverts sell an image."}]$$::jsonb,
    $$[{"insteadOf":"make people buy","try":["influence buying decisions","shape consumer behaviour","encourage purchases"],"meaning":"affect what people choose","example":"Advertising shapes consumer behaviour.","context":"Use for advertising topics."},{"insteadOf":"famous brand","try":["recognisable brand","well-known brand","trusted brand"],"meaning":"a brand people know","example":"Recognisable brands often feel safer.","context":"Use for shopping decisions."},{"insteadOf":"good image","try":["desirable lifestyle","social status","emotional appeal"],"meaning":"the feeling a product is linked with","example":"The advert uses emotional appeal.","context":"Use for marketing effects."}]$$::jsonb,
    $$[{"pattern":"Advertising affects ___ by ___.","example":"Advertising affects buying decisions by creating familiarity.","suitableUse":"Explaining influence."},{"pattern":"They often sell ___ as much as ___.","example":"They often sell an image as much as the item itself.","suitableUse":"Adding insight."},{"pattern":"A strong advert may ___, but ___.","example":"A strong advert may attract attention, but bad reviews can stop a purchase.","suitableUse":"Balanced argument."}]$$::jsonb,
    $$[{"incorrect":"Advertisement can control people buy things.","better":"Advertising can influence what people buy.","why":"Influence is more accurate and needs what people buy."},{"incorrect":"People will trust because see many times.","better":"People may trust it because they see it many times.","why":"Include the object and subject."},{"incorrect":"Adverts make product attractive feeling.","better":"Adverts make products seem attractive.","why":"Use seem attractive."}]$$::jsonb
  ),
  (
    'part-3-advertising-and-consumer-behaviour',
    2,
    $$Are online reviews more important than advertising?$$,
    null::text,
    '[]'::jsonb,
    '[]'::jsonb,
    '[]'::jsonb,
    $$In many cases, online reviews are more trusted because they seem to come from real users.$$,
    $$Advertising shows what a company wants customers to believe, while reviews describe experiences after people have actually used the product.$$,
    $$For instance, a hotel may look attractive in an advert, but recent reviews about noise or cleanliness can strongly affect a customer's decision.$$,
    $$Still, reviews can also be manipulated or unbalanced, so consumers should not trust them blindly.$$,
    $$Online reviews are often more important because people think they are more honest. Advertising is made by companies, so it usually shows only the good side. Reviews can show real problems, such as poor service or low quality. However, some reviews may be fake or too emotional.$$,
    $$I think online reviews are often more persuasive than advertising because they feel closer to real experience. An advert can introduce a product, but reviews help people judge whether the product actually works. For example, before booking a hotel, many people check comments about cleanliness, location, and service. Still, reviews are not perfect because some may be fake or based on one unusual experience.$$,
    $$Online reviews can be more important than advertising, especially for products or services where trust matters. Advertising creates awareness, but reviews reduce uncertainty. They give potential customers details that adverts usually avoid, such as delivery problems, durability, or after-sales service. For example, a restaurant may have beautiful promotional photos, but repeated reviews about slow service can change people's minds quickly. That said, reviews need to be read critically, because extreme opinions and fake comments can distort the overall picture.$$,
    $$[{"phrase":"closer to real experience","meaning":"more connected to actual use","example":"Reviews feel closer to real experience."},{"phrase":"reduce uncertainty","meaning":"make people feel less unsure","example":"Reviews reduce uncertainty before buying."},{"phrase":"after-sales service","meaning":"help after a product is bought","example":"Reviews often mention after-sales service."},{"phrase":"read critically","meaning":"judge carefully, not blindly","example":"Reviews need to be read critically."}]$$::jsonb,
    $$[{"insteadOf":"company advertisement","try":["company advertising","promotional content","marketing message"],"meaning":"information made to sell something","example":"Promotional content shows the best side.","context":"Use for marketing."},{"insteadOf":"real people's words","try":["user reviews","customer feedback","first-hand experience"],"meaning":"opinions from customers","example":"Customer feedback feels trustworthy.","context":"Use for reviews."},{"insteadOf":"fake comments","try":["fake reviews","manipulated reviews","extreme opinions"],"meaning":"unreliable online comments","example":"Fake reviews can mislead buyers.","context":"Use for online trust."}]$$::jsonb,
    $$[{"pattern":"An advert can ___, but reviews can ___.","example":"An advert can create interest, but reviews can reveal problems.","suitableUse":"Comparing advertising and reviews."},{"pattern":"For products where ___ matters, ___ becomes important.","example":"For products where trust matters, reviews become important.","suitableUse":"Giving conditions."},{"pattern":"That said, ___ should be ___.","example":"That said, reviews should be read critically.","suitableUse":"Adding caution."}]$$::jsonb,
    $$[{"incorrect":"Reviews are more believe.","better":"Reviews are more believable.","why":"Use believable as the adjective."},{"incorrect":"Advertisement shows good side only.","better":"Advertising usually shows only the good side.","why":"Use advertising as an uncountable noun."},{"incorrect":"People should not trust blindly reviews.","better":"People should not trust reviews blindly.","why":"Place blindly after the verb phrase."}]$$::jsonb
  )
)
